import React, { useEffect, useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { 
  Box, 
  Container, 
  Grid, 
  Paper, 
  Typography, 
  Button, 
  Card, 
  CardContent, 
  Divider,
  List,
  ListItem,
  ListItemText,
  ListItemAvatar,
  Avatar,
  CircularProgress,
  Alert
} from '@mui/material';
import {
  AccountBalanceWallet,
  Send,
  Chat,
  SwapHoriz,
  Assessment,
  ArrowUpward,
  ArrowDownward,
  Error
} from '@mui/icons-material';
import api from '../utils/api';
import { useAuth } from '../context/AuthContext';

const Dashboard = () => {
  console.log("=== Dashboard Component Rendering ===");
  const { currentUser, isAuthenticated } = useAuth();
  console.log("Auth state:", { isAuthenticated, currentUser });

  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [wallets, setWallets] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [error, setError] = useState(null);
  const [totalBalance, setTotalBalance] = useState(0);
  const [debug, setDebug] = useState({});

  // Use ref to track if currentUser has changed in a meaningful way
  const prevUserIdRef = useRef(null);
  const hasUserChanged = currentUser?.id !== prevUserIdRef.current;

  useEffect(() => {
    console.log("Dashboard useEffect triggered", { isAuthenticated, userId: currentUser?.id });
    // Store current user ID in ref
    prevUserIdRef.current = currentUser?.id;

    const fetchDashboardData = async () => {
      console.log('Dashboard: Starting data fetch. User ID:', currentUser?.id);

      // Only refetch if this is the first load OR if user has changed
      // Temporarily disable caching for debugging
      const shouldRefetch = true;

      if (!shouldRefetch) {
        console.log('Dashboard: Using cached data, skipping API requests');
        setLoading(false);
        return;
      }

      console.log('Dashboard: Fetching fresh data...');

      setLoading(true);
      setError(null);
      let debugData = { 
        attempts: {}, 
        responses: {},
        currentUser: currentUser ? { ...currentUser, id: currentUser.id } : null,
        isAuthenticated,
        timestamp: new Date().toISOString()
      };

      try {
        // Fetch wallets
        try {
          console.log('Dashboard: Fetching wallet data...');
          let walletData = [];

          // Try user-specific wallet endpoint if we have a user ID
          if (currentUser && currentUser.id) {
            try {
              debugData.attempts.userWallet = `Attempting to fetch wallet for user ${currentUser.id}`;
              console.log(`Dashboard: Fetching wallet for user ${currentUser.id}`);

              // Include auth header explicitly for wallet request
              const walletsResponse = await api.get(`/wallet/${currentUser.id}`, {
                headers: {
                  'Authorization': `Bearer ${localStorage.getItem('auth_token')}`
                }
              });

              console.log('User specific wallet response:', walletsResponse.data);
              debugData.responses.userWallet = walletsResponse.data;

              // Convert to array if single object
              if (!Array.isArray(walletsResponse.data)) {
                walletData = [walletsResponse.data];
              } else {
                walletData = walletsResponse.data;
              }
            } catch (userWalletErr) {
              debugData.errors = debugData.errors || {};
              debugData.errors.userWallet = `Error: ${userWalletErr.message}`;
              console.warn('Could not fetch user-specific wallet:', userWalletErr);
            }
          } else {
            console.warn('Dashboard: No user ID available for wallet fetch');
            debugData.errors = debugData.errors || {};
            debugData.errors.noUserId = 'No user ID available for wallet fetch';
          }

          console.log('Dashboard: Setting wallet data:', walletData);
          setWallets(walletData || []);

          // Calculate total balance across all wallets
          const total = (walletData || []).reduce((sum, wallet) => 
            sum + parseFloat(wallet.fiat_balance || wallet.balance || 0), 0);
          setTotalBalance(total);

        } catch (walletErr) {
          debugData.errors = debugData.errors || {};
          debugData.errors.wallet = `Error: ${walletErr.message}`;
          console.error('Error fetching wallets:', walletErr);
          setWallets([]);
          setTotalBalance(0);
        }

        // Fetch recent transactions with similar pattern for debugging
        try {
          console.log('Dashboard: Fetching transaction data...');
          let transactionsData = [];

          // Try user-specific transactions first
          if (currentUser && currentUser.id) {
            try {
              debugData.attempts.userTransactions = `Attempting to fetch transactions for user ${currentUser.id}`;
              console.log(`Dashboard: Fetching transactions for user ${currentUser.id}`);

              const userTxResponse = await api.get(`/transaction/user/${currentUser.id}`, {
                headers: {
                  'Authorization': `Bearer ${localStorage.getItem('auth_token')}`
                }
              });

              console.log('User transactions response:', userTxResponse.data);
              debugData.responses.userTransactions = userTxResponse.data;

              if (Array.isArray(userTxResponse.data)) {
                transactionsData = userTxResponse.data;
              } else if (userTxResponse.data && Array.isArray(userTxResponse.data.transactions)) {
                transactionsData = userTxResponse.data.transactions;
              }
            } catch (userTxErr) {
              debugData.errors = debugData.errors || {};
              debugData.errors.userTransactions = `Error: ${userTxErr.message}`;
              console.warn('Could not fetch user transactions:', userTxErr);
            }
          } else {
            console.warn('Dashboard: No user ID available for transaction fetch');
          }

          // Process and format the transaction data
          console.log('Dashboard: Processing transaction data:', transactionsData);
          const processedTransactions = transactionsData.map(tx => ({
            ...tx,
            formattedAmount: formatCurrency(tx.amount || tx.source_amount || 0, tx.currency || tx.source_currency || 'USD'),
            formattedDate: tx.timestamp ? formatDate(tx.timestamp) : 'N/A',
            type: determineTransactionType(tx, currentUser?.id)
          }));

          setTransactions(processedTransactions || []);

        } catch (txErr) {
          debugData.errors = debugData.errors || {};
          debugData.errors.transaction = `Error: ${txErr.message}`;
          console.error('Error fetching transactions:', txErr);
          setTransactions([]);
        }

        setDebug(debugData);
      } catch (err) {
        console.error('Error fetching dashboard data:', err);
        setError('Failed to load dashboard data. Please try again.');
        setDebug({
          ...debug,
          lastError: err.message,
          errorStack: err.stack
        });
      } finally {
        setLoading(false);
      }
    };

    if (isAuthenticated) {
      fetchDashboardData();
    } else {
      setLoading(false);
    }
  }, [isAuthenticated, currentUser?.id]); // Only re-fetch when authentication status or user ID changes

  const determineTransactionType = (transaction, userId) => {
    if (transaction.type) return transaction.type;
    if (transaction.transaction_type) return transaction.transaction_type;

    // If we have the user ID, determine if it's a send or receive
    if (userId) {
      if (transaction.sender_id === userId) return 'SEND';
      if (transaction.recipient_id === userId) return 'RECEIVE';
    }

    return 'UNKNOWN';
  };

  const formatCurrency = (amount, currency = 'USD') => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency
    }).format(amount || 0);
  };

  const formatDate = (dateString) => {
    const options = { year: 'numeric', month: 'short', day: 'numeric' };
    return new Date(dateString).toLocaleDateString('en-US', options);
  };

  const getTransactionIcon = (type) => {
    const typeUpper = String(type).toUpperCase();
    if (typeUpper === 'DEPOSIT' || typeUpper === 'RECEIVE') return <ArrowDownward color="success" />;
    if (typeUpper === 'WITHDRAWAL' || typeUpper === 'SEND') return <ArrowUpward color="error" />;
    return <SwapHoriz color="primary" />;
  };

  // IMPORTANT: Show debug panel at the top for troubleshooting
  const renderDebugPanel = () => (
    <Grid item xs={12}>
      <Paper sx={{ p: 2, mt: 2, border: '2px solid red' }}>
        <Typography variant="h6" gutterBottom sx={{ color: 'red' }}>
          Debug Information
        </Typography>
        <Box 
          component="pre" 
          sx={{ 
            p: 2, 
            backgroundColor: '#f5f5f5', 
            borderRadius: 1,
            maxHeight: '300px',
            overflow: 'auto',
            fontSize: '0.8rem'
          }}
        >
          {JSON.stringify({
            currentUser: currentUser ? { ...currentUser, id: currentUser.id } : null,
            isAuthenticated,
            loading,
            walletsCount: wallets.length,
            transactionsCount: transactions.length,
            error,
            debug
          }, null, 2)}
        </Box>
      </Paper>
    </Grid>
  );

  if (!isAuthenticated) {
    return (
      <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
        {renderDebugPanel()}
        <Box display="flex" flexDirection="column" justifyContent="center" alignItems="center" minHeight="80vh">
          <Error sx={{ fontSize: 60, color: 'error.main', mb: 2 }} />
          <Typography variant="h5" gutterBottom>
            Authentication Required
          </Typography>
          <Typography variant="body1" color="text.secondary" align="center" sx={{ mb: 3, maxWidth: 500 }}>
            Please log in to view your dashboard and access TerraFlow features.
          </Typography>
          <Button 
            variant="contained" 
            onClick={() => navigate('/login')}
          >
            Go to Login
          </Button>
        </Box>
      </Container>
    );
  }

  if (loading) {
    return (
      <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
        {renderDebugPanel()}
        <Box display="flex" justifyContent="center" alignItems="center" minHeight="80vh">
          <CircularProgress />
        </Box>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
      <Grid container spacing={3}>
        {/* Debug panel at the top */}
        {renderDebugPanel()}

        {/* Welcome Section */}
        <Grid item xs={12}>
          <Paper sx={{ p: 3, display: 'flex', flexDirection: 'column' }}>
            <Typography variant="h4" gutterBottom>
              Welcome, {currentUser?.username || 'User'}
            </Typography>
            <Typography variant="body1" color="text.secondary">
              Here's an overview of your account
            </Typography>
            <Box mt={2}>
              <Typography variant="caption" color="text.secondary">
                User ID: {currentUser?.id || 'Unknown'} | Authentication: {isAuthenticated ? 'Yes' : 'No'}
              </Typography>
            </Box>
          </Paper>
        </Grid>

        {error && (
          <Grid item xs={12}>
            <Alert severity="error">{error}</Alert>
          </Grid>
        )}

        {/* Wallet info */}
        <Grid item xs={12}>
          <Paper sx={{ p: 2 }}>
            <Typography variant="h6" gutterBottom>
              Your Wallet Information
            </Typography>
            {wallets.length === 0 ? (
              <Typography color="error">No wallet data found</Typography>
            ) : (
              <Box>
                {wallets.map((wallet, index) => (
                  <Card key={index} sx={{ mb: 2 }}>
                    <CardContent>
                      <Typography variant="subtitle1">
                        Wallet ID: {wallet.id || 'N/A'} | User ID: {wallet.user_id}
                      </Typography>
                      <Typography variant="h5">
                        Balance: {formatCurrency(wallet.fiat_balance || 0, wallet.currency)}
                      </Typography>
                      <Typography variant="body2">
                        Currency: {wallet.currency}
                      </Typography>
                    </CardContent>
                  </Card>
                ))}
              </Box>
            )}
          </Paper>
        </Grid>

        {/* Transactions info */}
        <Grid item xs={12}>
          <Paper sx={{ p: 2 }}>
            <Typography variant="h6" gutterBottom>
              Your Transactions
            </Typography>
            {transactions.length === 0 ? (
              <Typography color="error">No transaction data found</Typography>
            ) : (
              <List>
                {transactions.map((transaction, index) => (
                  <ListItem key={index}>
                    <ListItemText
                      primary={`ID: ${transaction.id} - ${transaction.type || 'Unknown'}`}
                      secondary={`Amount: ${formatCurrency(transaction.source_amount, transaction.source_currency)} | Date: ${formatDate(transaction.timestamp)}`}
                    />
                  </ListItem>
                ))}
              </List>
            )}
          </Paper>
        </Grid>
      </Grid>
    </Container>
  );
};

export default Dashboard;
